/**
 * HMAC must match the exact raw JSON string sent in the HTTP body.
 * n8n Cloud: set variable RESIN_EMAIL_WEBHOOK_SECRET (Settings → Variables) and use:
 *   const secret = $vars.RESIN_EMAIL_WEBHOOK_SECRET;
 * Self-hosted: process.env often works.
 */
let secret = '';
try {
  secret = typeof $vars !== 'undefined' && $vars.RESIN_EMAIL_WEBHOOK_SECRET
    ? String($vars.RESIN_EMAIL_WEBHOOK_SECRET)
    : '';
} catch (e) {
  secret = '';
}
if (!secret && typeof process !== 'undefined' && process.env && process.env.RESIN_EMAIL_WEBHOOK_SECRET) {
  secret = String(process.env.RESIN_EMAIL_WEBHOOK_SECRET);
}
if (!secret) {
  throw new Error('Set RESIN_EMAIL_WEBHOOK_SECRET (n8n Variable) or process.env for self-hosted.');
}
const crypto = require('crypto');
const j = $input.first().json;
const fromVal = j.from?.value?.[0]?.address || j.from?.text || j.from || j.headers?.from || '';
let fromEmail = String(fromVal).trim();
const angle = fromEmail.match(/<([^>]+)>/);
if (angle) fromEmail = angle[1].trim();
const fromName = j.from?.value?.[0]?.name || '';
const subject = j.subject || '(no subject)';
const textBody = j.text || j.textPlain || j.snippet || '';
const externalMessageId = j.id || j.messageId;
const toFirst = j.to?.value?.[0]?.address || j.to?.text || '';
const payload = {
  fromEmail,
  fromName: fromName || undefined,
  toEmail: toFirst || undefined,
  subject,
  textBody,
  externalMessageId: externalMessageId || undefined,
};
const rawBody = JSON.stringify(payload);
const signature = crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
return [{ json: { rawBody, signature } }];
